MERGE INTO CONSULTAS FIN USING (SELECT '002657IndiceInmueblesFacturacion' INFORME ,TO_CLOB(q'[SELECT
    CASE EDIFICIO WHEN  1 THEN 'Ascensores'               WHEN 2 THEN 'Pedregal'               WHEN 3 THEN 'RTN'               WHEN 4 THEN 'Bachue'               WHEN 5 THEN 'RTS'               WHEN 6 THEN 'Bochica'               WHEN 7 THEN '0001'               WHEN 8 THEN '0003' END EDIFICIO,
    CASE TIPO WHEN 1 THEN 'Local'           WHEN 2 THEN 'Mezzanine'           WHEN 3 THEN 'Bodega'           WHEN 4 THEN 'Sótano'            WHEN 5 THEN 'Oficina'           WHEN 6 THEN 'Piso'           WHEN 7 THEN 'Casa'           WHEN 8 THEN 'Lote'           WHEN 9 THEN 'Plazoleta'           WHEN 10 THEN 'Galeria Bochica'           WHEN 11 THEN 'Edificio'           WHEN 12 THEN 'Terraza'           WHEN 13 THEN 'Baño'           WHEN 14 THEN 'Pasillo'           WHEN 15 THEN 'Espacio' END AS INMUEBLES,
    COUNT(CASE WHEN ARRENDADO NOT IN (0) THEN 1 END) AS INMUEBLES_ARRENDADOS,
    COUNT(CASE WHEN DISPONIBLE NOT IN (0) THEN 1 END) AS INMUEBLES_LIBRES,
    COUNT(*) AS TOTAL_INMUEBLES,
    SUM(CASE WHEN ARRENDADO  NOT IN (0) THEN AREA ELSE 0 END) AS AREA_ARRRENDADA,
    SUM(CASE WHEN DISPONIBLE  NOT IN (0) THEN AREA ELSE 0 END) AS AREA_DISPONIBLE,
    SUM(AREA) AS TOTAL_AREA
FROM
    INMUEBLE_FACTURACION
WHERE
    ACTIVO NOT IN (0)
    AND COMPANIA = 's$compania$s'
    AND EDIFICIO BETWEEN 's$edificioinicial$s' AND 's$edificiofinal$s'
    AND CODIGOINMUEBLE BETWEEN 's$codigoinmuebleincial$s' AND 's$codigoinmueblefinal$s'
GROUP BY
    EDIFICIO, TIPO
ORDER BY
    EDIFICIO, TIPO]') CONSULTA, 69 APLICACION ,TO_CLOB(q'[]') CONSULTA_OPCIONAL, 'mrosero' CREATED_BY, NULL MODIFIED_BY  FROM DUAL ) INI ON (INI.INFORME = FIN.INFORME )  WHEN MATCHED THEN  UPDATE SET FIN.CONSULTA =  INI.CONSULTA, FIN.APLICACION =  INI.APLICACION, FIN.CONSULTA_OPCIONAL =  INI.CONSULTA_OPCIONAL, FIN.MODIFIED_BY = INI.MODIFIED_BY, FIN.DATE_MODIFIED = SYSDATE  WHEN NOT MATCHED THEN  INSERT (INFORME,CONSULTA, APLICACION,CONSULTA_OPCIONAL,CREATED_BY,DATE_CREATED)  VALUES (INI.INFORME,INI.CONSULTA, INI.APLICACION,INI.CONSULTA_OPCIONAL,INI.CREATED_BY,SYSDATE);